from collections import defaultdict

class Solution(object):
    def maxSum(self, nums, m, k):
        freq = defaultdict(int)
        window_sum = 0
        ans = 0
        for i in range(len(nums)):
            freq[nums[i]] += 1
            window_sum += nums[i]
            if i >= k:
                old = nums[i - k]
                freq[old] -= 1
                if freq[old] == 0:
                    del freq[old]
                window_sum -= old
            if i >= k - 1 and len(freq) >= m:
                ans = max(ans, window_sum)
        return ans
